WITH report_updates(club_name, user_phone, old_message, new_message, new_status, new_created_at) AS (
    VALUES
        ('Импульс', '+79030000011', 'Не проходит оплата будущей брони картой, заказ остается в ожидании.', 'Добавьте, пожалуйста, больше указателей внутри здания, вход в клуб с первого раза найти сложно.', 'NEW', localtimestamp - interval '4 hours'),
        ('Импульс', '+79991234567', 'Администратор на стойке грубо ответил и не помог с переносом брони.', 'Администратор на стойке грубо ответил и не помог с переносом брони.', 'NEW', localtimestamp - interval '1 day'),
        ('Импульс', '+79030000010', 'В VIP-комнате вечером было душно, проверьте кондиционер.', 'В VIP-комнате вечером было душно, проверьте кондиционер.', 'IN_PROGRESS', localtimestamp - interval '9 hours'),
        ('Северный Портал', '+79030000003', 'На месте A2 периодически пропадает звук в гарнитуре.', 'На месте A2 периодически пропадает звук в гарнитуре.', 'NEW', localtimestamp - interval '3 hours'),
        ('Северный Портал', '+79030000004', 'На стойке долго ждали администратора для подтверждения ночной брони.', 'На стойке долго ждали администратора для подтверждения ночной брони.', 'NEW', localtimestamp - interval '6 hours'),
        ('Северный Портал', '+79030000005', 'После групповой брони заказ с напитками выдали только через 20 минут.', 'После групповой брони заказ с напитками выдали только через 20 минут.', 'IN_PROGRESS', localtimestamp - interval '1 day'),
        ('Северный Портал', '+79030000013', 'После отмены брони уведомление еще несколько часов показывало ее как активную.', 'Добавьте у обычного зала несколько крючков или полок для рюкзаков, вещи неудобно держать рядом.', 'RESOLVED', localtimestamp - interval '6 days'),
        ('Линия Пикселей', '+79030000009', 'На месте B2 залипает клавиша Shift, нужна замена клавиатуры.', 'На месте B2 залипает клавиша Shift, нужна замена клавиатуры.', 'NEW', localtimestamp - interval '5 hours'),
        ('Линия Пикселей', '+79030000006', 'Сотрудник долго не мог помочь с заменой мыши на месте B4.', 'Сотрудник долго не мог помочь с заменой мыши на месте B4.', 'NEW', localtimestamp - interval '7 hours'),
        ('Линия Пикселей', '+79030000008', 'Нужна помощь с возвратом за отмененное VIP-бронирование.', 'В зоне ожидания мало мест, во время вечерней загрузки негде спокойно подождать друзей.', 'IN_PROGRESS', localtimestamp - interval '2 days')
)
UPDATE club_user_reports AS r
SET message = u.new_message,
    status = u.new_status,
    created_at = u.new_created_at
FROM report_updates AS u
JOIN clubs AS c ON c.name = u.club_name
JOIN users AS usr ON usr.phone = u.user_phone
WHERE r.club_id = c.id
  AND r.user_id = usr.id
  AND r.message = u.old_message;

WITH warning_updates(club_name, old_message, new_message, new_created_at) AS (
    VALUES
        ('Импульс', 'Проверьте карточку клуба: обновите описание и добавьте актуальные фото входной группы.', 'В карточке клуба не хватает актуальных фото входа и навигации внутри здания.', localtimestamp - interval '3 days'),
        ('Импульс', 'По клубу поступило несколько жалоб на вечернюю смену администраторов. Проведите внутреннюю проверку.', 'По клубу поступило несколько жалоб на работу вечерней смены администраторов.', localtimestamp - interval '8 hours'),
        ('Северный Портал', 'После перестановки мест обновите схему зала и подписи VIP-секции.', 'На схеме зала не совпадает часть подписей мест после последней перестановки.', localtimestamp - interval '4 days'),
        ('Северный Портал', 'Проверьте, что новые позиции в каталоге отмечены как доступные и с актуальными ценами.', 'В каталоге клуба у части новых позиций нет финальных цен или статуса доступности.', localtimestamp - interval '12 hours'),
        ('Линия Пикселей', 'В каталоге есть позиции без актуальных фото. Обновите карточки товаров.', 'В каталоге клуба у нескольких товаров нет актуальных фотографий.', localtimestamp - interval '2 days'),
        ('Линия Пикселей', 'После обновления расстановки проверьте схему зала в приложении и доступность мест.', 'После обновления схемы проверьте, что все места на плане отображаются в своих зонах.', localtimestamp - interval '1 day')
)
UPDATE club_warning AS w
SET message = u.new_message,
    created_at = u.new_created_at
FROM warning_updates AS u
JOIN clubs AS c ON c.name = u.club_name
WHERE w.club_id = c.id
  AND w.message = u.old_message;
